#include <bits/stdc++.h>
using namespace std;
const int N=5e5+5,mod=998244353;
int n,a[N];
long long k,ans[N],s[N];
vector<int> g[N]; 
int main(){
	scanf("%d%lld",&n,&k);
	for(int i=0,x;i<=n;i++){
		scanf("%d",&a[i]);
		for(int j=0;j<a[i];j++){
			scanf("%d",&x);
			g[i].push_back(x);
		}
	}
	queue<int> q;
	q.push(0);
	while(q.size()){
		int f=q.front();
		q.pop();
		if(s[f]==k)
			break;
		for(int i=0;i<a[f];i++){
			int v=g[f][i];
			if(!s[v])
				ans[v]=1LL*a[v]*((k-s[f])%mod)%mod,s[v]=s[f]+1,q.push(v);
			ans[v]+=k-s[f],ans[v]%=mod;
		}
	}
	for(int i=1;i<=n;i++)
		printf("%lld ",ans[i]);
	return 0;
}
